function _readAndResizeAvatar(file,cb){if(!file)return;if(file.size>2*1024*1024){toast(t("t_avatar_too_large"),3000,"err");return}var reader=new FileReader();reader.onload=function(){var img=new Image();img.onload=function(){var canvas=document.createElement("canvas");canvas.width=256;canvas.height=256;var ctx=canvas.getContext("2d");var size=Math.min(img.width,img.height);var sx=(img.width-size)/2,sy=(img.height-size)/2;ctx.drawImage(img,sx,sy,size,size,0,0,256,256);canvas.toBlob(function(blob){cb(blob,canvas.toDataURL("image/jpeg",0.85))},"image/jpeg",0.85)};img.onerror=function(){toast(t("t_avatar_err"),3000,"err")};img.src=reader.result};reader.readAsDataURL(file)}
