function setupOtp(rowId,onComplete){var row=$(rowId);if(!row)return;var cells=row.querySelectorAll(".otp-cell");function getValue(){var s="";cells.forEach(function(c){s+=c.value||""});return s}cells.forEach(function(cell,i){cell.addEventListener("input",function(e){var v=cell.value.replace(/\D/g,"");cell.value=v.charAt(v.length-1)||"";cell.classList.toggle("filled",!!cell.value);if(cell.value&&cells[i+1])cells[i+1].focus();if(getValue().length===6&&typeof onComplete==="function")onComplete(getValue())});cell.addEventListener("keydown",function(e){if(e.key==="Backspace"&&!cell.value&&cells[i-1]){cells[i-1].focus();cells[i-1].value="";cells[i-1].classList.remove("filled");e.preventDefault()}if(e.key==="ArrowLeft"&&cells[i-1]){cells[i-1].focus();e.preventDefault()}if(e.key==="ArrowRight"&&cells[i+1]){cells[i+1].focus();e.preventDefault()}});cell.addEventListener("paste",function(e){e.preventDefault();var pasted=(e.clipboardData||window.clipboardData).getData("text").replace(/\D/g,"").slice(0,6);for(var k=0;k<pasted.length&&i+k<cells.length;k++){cells[i+k].value=pasted.charAt(k);cells[i+k].classList.add("filled")}var nextEmpty=i+pasted.length;if(nextEmpty<cells.length)cells[nextEmpty].focus();if(getValue().length===6&&typeof onComplete==="function")onComplete(getValue())})});row.getOtp=getValue;row.clearOtp=function(){cells.forEach(function(c){c.value="";c.classList.remove("filled")});cells[0].focus()}}
