function bootstrap(){var qs=new URLSearchParams(location.search);var oauthTk=qs.get("token");if(oauthTk){setAuthToken(oauthTk);qs.delete("token");var qstr=qs.toString();history.replaceState({},"",location.pathname+(qstr?"?"+qstr:""))}var tk=authToken();/* Hide login during the probe if we have a token — avoids a flash of the
   login screen on every refresh while /api/auth/me is in flight. */if(tk){$("loginScreen").classList.add("hidden")}var probeUrl=tk?"/api/auth/me":"/api/health";var probeOpts=tk?{headers:{"Authorization":"Bearer "+tk}}:{};fetch(API_BASE+probeUrl,probeOpts).then(function(r){if(tk){if(r.ok)return r.json().then(function(u){applySession(u);if(u.is_verified&&!u.profile_completed){showProfileSetup();return}if(u.is_verified&&u.profile_completed&&u.is_approved===false){showPendingScreen();return}showApp();fetchPatients();if(typeof refreshAdminPending==="function")refreshAdminPending();if(typeof refreshNotifs==="function")refreshNotifs()});/* Only invalidate the token on real auth failures (401 / 403). For
   transient backend issues (500, 502, 503, 504) keep the user signed in
   and let them retry — wiping the token here forces a relogin every
   time Railway hiccups. */if(r.status===401||r.status===403){setAuthToken("");showLogin();return}showLogin();return}showLogin()}).catch(function(){if(tk){/* Network error with a token in pocket: probably transient. Keep the
   token, show login as a fallback so the user can act, but don't wipe
   credentials — next refresh will retry the probe. */showLogin();return}enterDemoMode()})}

