function bePatToFe(p){return{id:String(p.id),_serverId:p.id,name:p.full_name||"",ini:p.initials||(p.full_name||"").split(/\s+/).map(function(w){return w[0]||""}).join("").slice(0,2).toUpperCase(),ward:p.ward||"",ward_en:p.ward_en||p.ward||"",department:p.department||"",status:p.status||"",patient_type:p.patient_type||"outpatient",score:(p.avris_score==null?null:p.avris_score),diag:p.diagnoses||[],diag_en:p.diagnoses_en||p.diagnoses||[],current:p.current_conditions||p.diagnoses||[],current_en:p.current_conditions_en||p.diagnoses_en||[],hist:p.history||[],hist_en:p.history_en||p.history||[],allergy:p.allergies||[],allergy_en:p.allergies_en||p.allergies||[],meds:p.medications||[],meds_en:p.medications_en||p.medications||[],insight:p.insight||"",insight_en:p.insight_en||p.insight||"",demo:{age:p.age,gender:p.gender||"",gender_en:p.gender_en||p.gender||"",blood:p.blood_type||"",blood_en:p.blood_type_en||p.blood_type||"",height:p.height,weight:p.weight,bmi:p.bmi||""},vitals:p.vitals||{}}}
