/* Null-safe Avris Score class+label. Returns {cls,label} where cls is one of
   "danger|warn|safe|pending" and label is localized. New patients without an
   exam yet have score=null → pending (gray). */
/* 4-tier mapping. Frozen colours per spec:
   0-39 critical (#EF4444), 40-59 serious (#F59E0B),
   60-79 watch    (#EAB308), 80-100 stable    (#10B981).
   null = not yet examined → gray "pending" pill. */
function scoreInfo(score){
  if(score==null)return{cls:"pending",label:t("st_pending"),hex:"#8a98a8"};
  if(score<40)return{cls:"danger",label:t("st_crit"),hex:"#EF4444"};
  if(score<60)return{cls:"serious",label:t("st_serious"),hex:"#F59E0B"};
  if(score<80)return{cls:"watch",label:t("st_watch"),hex:"#EAB308"};
  return{cls:"safe",label:t("st_stab"),hex:"#10B981"};
}
