/* Format a meta line for the patient list. Inpatient: "Палата 5 · Кардиология · diag1 · diag2".
   Outpatient: "Амбулаторный · diag1". Skips empty parts so partially-filled
   patients still look clean. */
function _patMetaLine(p){
  var parts=[];
  var diagArr=(lang==="en"&&p.diag_en)?p.diag_en:(p.diag||[]);
  if(p.patient_type==="inpatient"){
    if(p.ward&&String(p.ward).trim())parts.push(t("w_label")+" "+esc(String(p.ward)));
    var deptKey=p.department?("dept_"+p.department):null;
    if(deptKey){var lbl=t(deptKey);if(lbl&&lbl!==deptKey)parts.push(esc(lbl))}
  }else{
    parts.push(esc(t("pt_outpatient")));
  }
  diagArr.forEach(function(d){if(d)parts.push(esc(d))});
  return parts.join(" · ");
}
