function attachSuggest(el,kind){if(!el||el.dataset.suggestAttached)return;el.dataset.suggestAttached="1";var activeIdx=-1,lastResults=[],current=null;var box=_suggestEnsureBox();function close(){box.hidden=true;activeIdx=-1;current=null;lastResults=[]}function pickItem(it){var info=_suggestTokenInfo(el);if(!info)return;var text=(kind==="icd10")?(it.code+" — "+(lang==="en"?it.name_en:it.name_ru)):(lang==="en"?it.name_en:it.name_ru);_suggestPick(el,info,text);close()}function showResults(items){activeIdx=-1;lastResults=items||[];current=el;if(!lastResults.length){close();return}box.innerHTML="";lastResults.forEach(function(it,i){var d=_suggestRenderItem(it,kind);d.onmousedown=function(e){e.preventDefault();pickItem(it)};box.appendChild(d)});_suggestPosition(box,el);box.hidden=false}el.addEventListener("input",function(){var info=_suggestTokenInfo(el);if(!info||info.token.length<2){close();return}clearTimeout(_suggestDebounce);if(_suggestAbort){try{_suggestAbort.abort()}catch(e){}_suggestAbort=null}_suggestDebounce=setTimeout(function(){if(window.DEMO_MODE&&kind==="icd10"){var q=info.token.toLowerCase();var matches=ICD10.filter(function(x){return x.c.toLowerCase().indexOf(q)===0||(x[lang]||x.ru).toLowerCase().indexOf(q)>=0}).slice(0,10).map(function(x){return{code:x.c,name_ru:x.ru,name_en:x.en}});showResults(matches);return}if(window.DEMO_MODE){close();return}var url=(kind==="icd10")?"/api/icd10/search":"/api/drugs/search";var ctrl=(typeof AbortController!=="undefined")?new AbortController():null;_suggestAbort=ctrl;var opts=ctrl?{signal:ctrl.signal}:{};apiFetch(url+"?q="+encodeURIComponent(info.token)+"&limit=10",opts).then(function(r){return r.ok?r.json():[]}).then(function(items){showResults(items||[])}).catch(function(){})},220)});el.addEventListener("keydown",function(e){if(box.hidden||current!==el)return;var items=box.querySelectorAll(".global-suggest-item");if(e.key==="ArrowDown"){e.preventDefault();activeIdx=Math.min(activeIdx+1,items.length-1);for(var i=0;i<items.length;i++)items[i].classList.toggle("active",i===activeIdx)}else if(e.key==="ArrowUp"){e.preventDefault();activeIdx=Math.max(activeIdx-1,0);for(var j=0;j<items.length;j++)items[j].classList.toggle("active",j===activeIdx)}else if(e.key==="Enter"&&activeIdx>=0){e.preventDefault();pickItem(lastResults[activeIdx])}else if(e.key==="Escape"){close()}});el.addEventListener("blur",function(){setTimeout(close,200)});window.addEventListener("scroll",function(){if(current===el&&!box.hidden)_suggestPosition(box,el)},true)}
