function findDdi(p){var conflicts=[];if(!p||!p.meds)return conflicts;var medsLow=p.meds.map(function(m){return(m||"").toLowerCase()});var alLow=(p.allergy||[]).map(function(a){return(a||"").toLowerCase()});medsLow.forEach(function(m,i){alLow.forEach(function(a){if(a&&m.indexOf(a)!==-1)conflicts.push({type:"allergy",text:t("ddi_allergy_match").replace("{drug}",p.meds[i]).replace("{allergy}",p.allergy[alLow.indexOf(a)])})})});DDI_PAIRS.forEach(function(pair){var hasA=medsLow.some(function(m){return m.indexOf(pair.a)!==-1});var hasB=medsLow.some(function(m){return m.indexOf(pair.b)!==-1});if(hasA&&hasB)conflicts.push({type:"pair",text:t(pair.risk)})});return conflicts}
function updatePatCtx(){var cp=$("consultPat");if(!cp)return;var p=patients.find(function(x){return x.id===cp.value});if(!p){$("patCtxAvatar").textContent="—";$("patCtxName").textContent=t("empty_pick_patient");$("patCtxMeta").textContent="—";var sc0=$("patCtxScore");if(sc0)sc0.style.display="none";var dg0=$("patCtxDiag");if(dg0)dg0.innerHTML="";var al0=$("patCtxAllergy");if(al0)al0.style.display="none";var ddi0=$("patCtxDdi");if(ddi0)ddi0.style.display="none";return}var si=scoreInfo(p.score);var wardTxt=(lang==="en"&&p.ward_en)?p.ward_en:p.ward;$("patCtxAvatar").textContent=p.ini;$("patCtxName").textContent=p.name;$("patCtxMeta").textContent=(p.demo&&p.demo.age?p.demo.age+t("years_short"):"")+(wardTxt?" · "+wardTxt:"");var sc=$("patCtxScore");sc.textContent=(p.score==null?si.label:(p.score+" "+si.label));sc.className="pat-ctx-score "+si.cls;sc.style.display="";var dg=$("patCtxDiag");var diagArr=(lang==="en"&&p.diag_en)?p.diag_en:p.diag;dg.innerHTML=diagArr.map(function(d){return'<span class="pat-ctx-diag">'+esc(d)+'</span>'}).join("");var al=$("patCtxAllergy");var alArr=(lang==="en"&&p.allergy_en)?p.allergy_en:p.allergy;if(alArr&&alArr.length){al.innerHTML=SVG_WARN+' '+alArr.map(esc).join(", ");al.style.display=""}else{al.style.display="none"}var ddi=$("patCtxDdi");var conflicts=findDdi(p);if(conflicts.length){ddi.innerHTML=SVG_WARN+' '+esc(t("ddi_label"));ddi.title=conflicts.map(function(c){return"• "+c.text}).join("\n");ddi.style.display=""}else{ddi.style.display="none"}}
