function buildQR(payload){var svg=$("labQrSvg");if(!svg)return;svg.innerHTML="";if(!payload){var cp=$("consultPat"),pid=(cp&&cp.value)||"unknown";var demoToken="demo-"+pid+"-"+Date.now();payload=LAB_PORTAL_BASE+"?token="+encodeURIComponent(demoToken)}if(typeof qrcode!=="function"){svg.setAttribute("viewBox","0 0 1 1");return}var qr=qrcode(0,"M");qr.addData(payload);qr.make();var n=qr.getModuleCount();svg.setAttribute("viewBox","0 0 "+n+" "+n);for(var y=0;y<n;y++){for(var x=0;x<n;x++){if(qr.isDark(y,x)){var r=document.createElementNS("http://www.w3.org/2000/svg","rect");r.setAttribute("x",x);r.setAttribute("y",y);r.setAttribute("width",1);r.setAttribute("height",1);r.setAttribute("fill","#000");svg.appendChild(r)}}}}
