(function(){var block=document.getElementById("examRecBlock"),pane=document.getElementById("cTabExam"),tt=$("transcriptText"),mic=$("micBtn");if(!block||!tt||!mic)return;var wasRec=false;
function setExamState(s){if(!pane)return;pane.classList.remove("exam-state-idle","exam-state-recording","exam-state-done");pane.classList.add("exam-state-"+s);if(s==="recording"){var nm=document.getElementById("examRecName"),pc=$("patCtxName");if(nm&&pc)nm.textContent=pc.textContent}}
window._setExamState=setExamState;
function refresh(){var raw=(tt.textContent||"").trim();var hasText=!!raw&&raw!==t("tr_ph");var recing=mic.classList.contains("rec");block.classList.toggle("has-transcript",hasText);block.classList.toggle("rec-active",recing);if(!hasText)block.classList.remove("saved");
/* Invisible-UI 3-state: .rec appears -> recording; .rec removed after a take -> done; otherwise stay idle (set in HTML / reset on clear). */
if(recing){setExamState("recording")}else if(wasRec){setExamState("done")}wasRec=recing}
new MutationObserver(refresh).observe(tt,{childList:true,subtree:true,characterData:true});new MutationObserver(refresh).observe(mic,{attributes:true,attributeFilter:["class"]});refresh()})();
