function startRec(){if(window.DEMO_MODE){recording=true;recStart=Date.now();$("micBtn").classList.add("rec");$("waveform").classList.add("rec");$("recInd").classList.add("on");$("transcriptText").textContent="";if($("recBarLabel"))$("recBarLabel").textContent=t("rec_stop")||"ОСТАНОВИТЬ ЗАПИСЬ";if($("recStatusLbl"))$("recStatusLbl").textContent=t("rec_recording")||"Идёт запись...";if($("transcriptMeta"))$("transcriptMeta").innerHTML='0 <span data-i18n="rec_words">'+t("rec_words")+'</span>';startTimer();startTypewriter();return}if(!navigator.mediaDevices||!navigator.mediaDevices.getUserMedia){toast(t("t_mic_err"),3000,"err");return}navigator.mediaDevices.getUserMedia({audio:true}).then(function(stream){recChunks=[];try{mediaRec=new MediaRecorder(stream,{mimeType:"audio/webm"})}catch(e){try{mediaRec=new MediaRecorder(stream)}catch(e2){stream.getTracks().forEach(function(tr){tr.stop()});toast(t("t_mic_err"),3000,"err");return}}mediaRec.ondataavailable=function(ev){if(ev.data&&ev.data.size>0)recChunks.push(ev.data)};mediaRec.onstop=function(){stream.getTracks().forEach(function(tr){tr.stop()});recDurationSec=recStart?Math.floor((Date.now()-recStart)/1000):0;var blob=new Blob(recChunks,{type:(mediaRec&&mediaRec.mimeType)||"audio/webm"});transcribeAudio(blob)};mediaRec.start();recording=true;recStart=Date.now();$("micBtn").classList.add("rec");$("waveform").classList.add("rec");$("recInd").classList.add("on");$("transcriptText").textContent="";if($("recBarLabel"))$("recBarLabel").textContent=t("rec_stop")||"ОСТАНОВИТЬ ЗАПИСЬ";if($("recStatusLbl"))$("recStatusLbl").textContent=t("rec_recording")||"Идёт запись...";if($("transcriptMeta"))$("transcriptMeta").innerHTML='0 <span data-i18n="rec_words">'+t("rec_words")+'</span>';startTimer()}).catch(function(){toast(t("t_mic_err"),3000,"err")})}
