function ddxGenerate(){var s=($("soapS").value||"").toLowerCase();var o=($("soapO").value||"").toLowerCase();var a=($("soapA").value||"").toLowerCase();var hay=s+" "+o+" "+a;function has(){for(var i=0;i<arguments.length;i++){if(hay.indexOf(arguments[i])===-1)return false}return true}if((has("головн","давлен")||has("headache","bp")||has("сар","фишор"))){return["I10","G43","G44"].map(function(c,i){var d=ddxByName(c);d.p=[85,45,30][i];return d})}if(has("грудь")||has("груди")||has("chest pain")||has("сина")){return["I20","I21","R07"].map(function(c,i){var d=ddxByName(c);d.p=[70,35,25][i];return d})}if((has("кашел","температур")||has("сулф","табларза")||has("cough","fever"))){return["J18","J06","J45"].map(function(c,i){var d=ddxByName(c);d.p=[65,80,20][i];return d})}var primary=$("soapA").value.trim()||t("ddx_default_unknown");var picks=ICD10.slice().sort(function(){return Math.random()-0.5}).slice(0,2);return[{c:"—",name:primary,p:90},{c:picks[0].c,name:picks[0][lang]||picks[0].ru,p:55},{c:picks[1].c,name:picks[1][lang]||picks[1].ru,p:35}]}
