function parseOneRound(text){var src=String(text||"").trim();if(!src)return null;var ward=null,m;m=src.match(/(?:[Пп]алата(?:и)?|[Ww]ard)\s*([A-ZА-Я]\s*\d+)/i);if(m)ward=m[1].replace(/\s+/g,"").toUpperCase();var lc=src.toLowerCase();var patient=null;for(var i=0;i<patients.length;i++){var p=patients[i];var fragments=[(p.name||"").split(" ")[0],(p.ini||""),(p.name||"")];var enName=p.full_name_en||"";if(enName)fragments.push(enName.split(" ")[0]);for(var j=0;j<fragments.length;j++){var f=(fragments[j]||"").toLowerCase().trim();if(f&&f.length>=3&&lc.indexOf(f)>=0){patient=p;break}}if(patient)break}var vitals={};m=src.match(/(?:[Пп]ульс|[Нн]абз|[Pp]ulse|HR)\s+(\d{2,3})/);if(m)vitals.pulse=parseInt(m[1]);m=src.match(/(?:[Дд]авлени[ея]|[Фф]ишор|[Bb][Pp])\s+(\d{2,3})\s*(?:на|ба|over|\/)\s*(\d{2,3})/);if(m)vitals.bp=m[1]+"/"+m[2];m=src.match(/(?:[Тт]емператур[а-я]*|[Ҳҳ]арорат|[Tt]emperature|[Tt]emp)[ ,.:]+\s*(\d{2}\.\d|\d{2,3})/);if(m)vitals.temp=parseFloat(m[1]);m=src.match(/(?:[Сс]атураци[яи]|[Сс]атуратси[яи]|[Ss]aturation|SpO2)\s+(\d{2,3})/);if(m)vitals.spo2=parseInt(m[1]);var status_val="stable";if(/тяж[её]л|вазнин|severe|serious/i.test(src))status_val="warning";if(/критическ|танкид|critical/i.test(src))status_val="danger";var notes=src.replace(/(?:[Пп]алата(?:и)?|[Ww]ard)\s*[A-ZА-Я]\s*\d+\s*[,.]?/i,"").trim();if(patient){var lname=(patient.name||"").split(" ")[0];if(lname)notes=notes.replace(new RegExp("^"+lname+"[,.]?\\s*","i"),"")}return{ward:ward,patient:patient,vitals:vitals,status:status_val,notes:notes,transcript:src}}
