function callDocOnDuty(patId){var pat=patients.find(function(p){return String(p.id)===String(patId)||p.name===patId});if(!pat){toast(t("t_doc_called"),2200,"ok");return}if(window.DEMO_MODE){toast(t("t_doc_called"),2200,"ok");return}var ov=$("callDocOv");if(!ov)return;$("callDocPatient").textContent=pat.name+(pat.ward?" · "+pat.ward:"");$("callDocReason").value="deterioration";$("callDocNote").value="";ov.dataset.serverPid=pat._serverId||"";ov.classList.add("show")}
if($("callDocClose"))$("callDocClose").onclick=function(){$("callDocOv").classList.remove("show")};
if($("callDocCancel"))$("callDocCancel").onclick=function(){$("callDocOv").classList.remove("show")};
if($("callDocSend"))$("callDocSend").onclick=function(){var ov=$("callDocOv");var sid=parseInt(ov.dataset.serverPid||"0",10);if(!sid){toast(t("t_doc_called"),2200,"ok");ov.classList.remove("show");return}var btn=this;btn.disabled=true;apiFetch("/api/notifications/call-doctor",{method:"POST",body:JSON.stringify({patient_id:sid,reason:$("callDocReason").value,note:$("callDocNote").value.trim()||null})}).then(function(r){if(r.ok)return r.json().then(function(d){var who=(d&&d.notified_doctor&&d.notified_doctor.full_name)||"";toast(t("t_doc_called")+(who?" — "+who:""),2500,"ok");ov.classList.remove("show");if(typeof refreshNotifs==="function")refreshNotifs()});return r.json().catch(function(){return{}}).then(function(d){toast((d&&typeof d.detail==="string")?d.detail:t("t_network"),2500,"err")})}).catch(function(){toast(t("t_network"),2500,"err")}).finally(function(){btn.disabled=false})};
function patientToIcu(p){var st=p.status||(p.score==null?"stable":(p.score<40?"critical":p.score<70?"warning":"stable"));if(st==="serious")st="warning";if(st==="watch")st="warning";var v=(p.vitals&&typeof p.vitals==="object"&&!Array.isArray(p.vitals))?p.vitals:{};function last(arr,d){return Array.isArray(arr)&&arr.length?arr[arr.length-1]:d}var hr=last(v["ЧСС"]||v.hr,80),bp=last(v["АД"]||v.sys,120);var sys=typeof bp==="number"?bp:120,dia=typeof v.dia==="number"?v.dia:80;var sp=last(v["SpO₂"]||v.spo2,97),temp=last(v["T°C"]||v.temp,36.6);var resp=last(v.resp,16);var bedT=p.department==="icu"?"icu":p.department==="post_icu"?"post":"icu";var bedNum=(p.ward||"").replace(/[^0-9]/g,"")||"—";return{id:p.id,name:p.name,ini:p.ini,bedT:bedT,bedN:bedNum,age:(p.demo&&p.demo.age)||null,gender:(p.demo&&p.demo.gender)||"",diag:(p.diag||[]).join(", ")||"—",notes:p.insight||"",status:st,doctor:(currentUser&&currentUser.last_name)||"",days:0,vitals:{hr:Math.round(hr),sys:Math.round(sys),dia:Math.round(dia),spo2:Math.round(sp),resp:Math.round(resp),temp:typeof temp==="number"?temp.toFixed(1):temp},upd:new Date().toTimeString().slice(0,5)}}
function renderICU(){var inpat=patients.filter(function(p){return p.patient_type!=="outpatient"});var icuList=inpat.filter(function(p){return p.department==="icu"}).map(patientToIcu);var postList=inpat.filter(function(p){return p.department==="post_icu"}).map(patientToIcu);renderICUGrid($("icuGrid"),icuList);renderICUGrid($("postIcuGrid"),postList);["icuGrid","postIcuGrid"].forEach(function(gid){var g=$(gid);if(!g||g._callBound)return;g._callBound=true;g.addEventListener("click",function(e){var b=e.target.closest('[data-act="callDoc"]');if(!b)return;e.preventDefault();e.stopPropagation();callDocOnDuty(b.dataset.pid)})});var all=icuList.concat(postList);var critCount=all.filter(function(p){return p.status==="critical"}).length;var avgSpo2=all.length?Math.round(all.reduce(function(s,p){return s+(p.vitals.spo2||0)},0)/all.length):0;var now=new Date();var hh=String(now.getHours()).padStart(2,"0");var mm=String(now.getMinutes()).padStart(2,"0");if($("icuTotalCount"))$("icuTotalCount").textContent=all.length;if($("icuCritCount"))$("icuCritCount").textContent=critCount;if($("icuAvgSpo2"))$("icuAvgSpo2").textContent=avgSpo2;if($("icuUpdTime"))$("icuUpdTime").textContent=t("icu_upd").toLowerCase()+" "+hh+":"+mm;var icuCrit=icuList.filter(function(p){return p.status==="critical"}).length;var icuWarn=icuList.filter(function(p){return p.status==="warning"}).length;if($("icuCritBadge")){var cb=$("icuCritBadge");if(icuCrit){cb.textContent=icuCrit+" "+t("icu_crit_n").toLowerCase();cb.style.display=""}else if(icuWarn){cb.textContent=icuWarn+" "+t("lbl_watch");cb.className="icu-sec-badge warn";cb.style.display=""}else cb.style.display="none"}if($("icuPostBadge")){var pb=$("icuPostBadge");pb.textContent=postList.length+" "+t("f_pat");pb.className="icu-sec-badge warn";pb.style.display=postList.length?"":"none"}}
function renderICUGrid(container,data){container.innerHTML="";if(!data||!data.length){container.innerHTML='<div class="empty-state"><svg aria-hidden="true" width="40" height="40" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.4" stroke-linecap="round" stroke-linejoin="round"><path d="M22 12h-4l-3 9L9 3l-3 9H2"/></svg><div class="empty-state-t">'+esc(t(container.id==="postIcuGrid"?"empty_post":"empty_icu"))+'</div></div>';return}data.forEach(function(p){var el=document.createElement("div");el.className="icu-c "+p.status;var stLabel=p.status==="critical"?t("icu_critical"):p.status==="warning"?t("icu_serious"):t("icu_stable");var v=p.vitals;var hrCls=v.hr>100?"alert":v.hr>90?"vwarn":"";var spCls=v.spo2<90?"alert":v.spo2<94?"vwarn":"";var bpCls=v.sys<90?"alert":v.sys<100?"vwarn":"";var callBtn=(p.status==="critical"||p.status==="warning")?'<button class="icu-call-btn2" type="button" data-act="callDoc" data-pid="'+esc(p.id||p.name)+'" aria-label="'+esc(t("icu_call_doc"))+'">'+SVG_BOLT+' '+t("icu_call_doc")+'</button>':"";var diagTxt=p.diagK?(t(p.diagK)||p.diag):p.diag;var notesTxt=p.notesK?(t(p.notesK)||p.notes):p.notes;var bedTxt=(p.bedT==="icu"?t("bed_icu"):t("bed_post"))+"-"+p.bedN;el.innerHTML='<div class="icu-ch"><div class="st-dot '+esc(p.status)+'"></div><div style="flex:1"><strong style="font-size:.9rem">'+esc(p.name)+'</strong><div style="font-size:.78rem;color:var(--text-subtle)">'+esc(bedTxt)+' · '+esc(diagTxt)+'</div></div><span class="badge '+(p.status==="critical"?"danger":p.status==="warning"?"warn":"safe")+'">'+esc(stLabel)+'</span></div><div class="icu-cb"><div class="icu-vg"><div class="icu-v '+hrCls+'"><div class="icu-vl">'+t("vital_hr")+'</div><div class="icu-vv">'+v.hr+'</div><div class="icu-vu">'+t("vital_hr_u")+'</div></div><div class="icu-v '+bpCls+'"><div class="icu-vl">'+t("vital_bp")+'</div><div class="icu-vv">'+v.sys+'/'+v.dia+'</div><div class="icu-vu">'+t("vital_bp_u")+'</div></div><div class="icu-v '+spCls+'"><div class="icu-vl">SpO₂</div><div class="icu-vv">'+v.spo2+'%</div><div class="icu-vu">'+t("vital_spo2_u")+'</div></div><div class="icu-v"><div class="icu-vl">'+t("vital_resp")+'</div><div class="icu-vv">'+v.resp+'</div><div class="icu-vu">'+t("vital_resp_u")+'</div></div><div class="icu-v"><div class="icu-vl">T°C</div><div class="icu-vv">'+v.temp+'</div><div class="icu-vu">'+t("vital_temp_u")+'</div></div><div class="icu-v"><div class="icu-vl">'+t("icu_days_short")+'</div><div class="icu-vv">'+p.days+'</div><div class="icu-vu">'+t("icu_attending")+'</div></div></div></div><div class="icu-cf">'+esc(notesTxt)+'<div class="icu-cf-footer">'+callBtn+'<span class="icu-upd-time">'+t("icu_upd")+': '+esc(p.upd)+'</span></div></div>';container.appendChild(el)})}
