function openModal(id){var p=patients.find(function(x){return x.id===id});if(!p)return;curModal=p;var wardTxt=(lang==="en"&&p.ward_en)?p.ward_en:p.ward;$("pmAvatar").textContent=p.ini;$("pmName").textContent=p.name;$("pmMeta").textContent=p.demo.age+t("years_short")+" · "+wardTxt;$("pmScoreVal").textContent=(p.score==null?"—":p.score);$("pmInsight").textContent=(lang==="en"&&p.insight_en)?p.insight_en:(p.insight||"");var ring=$("pmRing");ring.style.stroke=scoreInfo(p.score).hex;ring.style.strokeDashoffset=(p.score==null?PM_RING_C:PM_RING_C*(1-p.score/100));var vw=$("pmVitals");vw.innerHTML="";var vKeys=[{k:"ЧСС",label:t("vital_hr"),unit:t("vital_hr_unit"),norm:t("norm_hr")},{k:"АД",label:t("vital_bp"),unit:t("vital_bp_unit"),norm:t("norm_bp")},{k:"SpO₂",label:"SpO₂",unit:"%",norm:t("norm_spo2")}];vKeys.forEach(function(vi){var data=p.vitals[vi.k];var last=data?data[data.length-1]:"—";var div=document.createElement("div");div.className="pm-vital";var spark="";if(data&&data.length>1){var sw=80,sh=6;var mn=Math.min.apply(null,data),mx=Math.max.apply(null,data),rng=mx-mn||1;var pts=data.map(function(v,i){return(i*sw/(data.length-1))+","+((1-(v-mn)/rng)*sh)}).join(" ");spark='<svg aria-hidden="true" class="pm-sparkline" viewBox="0 0 '+sw+' '+sh+'" width="'+sw+'" height="'+sh+'"><polyline points="'+pts+'" fill="none" stroke="var(--accent)" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"/></svg>'}div.innerHTML='<div class="pm-vital-label">'+esc(vi.label)+'</div><div class="pm-vital-val">'+esc(String(last))+'</div><div class="pm-vital-unit">'+esc(vi.unit)+'</div><div class="pm-vital-norm">'+esc(vi.norm)+'</div>'+spark;vw.appendChild(div)});var d=p.demo;var genderTxt=(lang==="en"&&d.gender_en)?d.gender_en:(d.gender==="Ж"?t("gender_f"):t("gender_m"));var bloodTxt=(lang==="en"&&d.blood_en)?d.blood_en:d.blood;$("pmProfile").innerHTML="<span>"+t("lbl_age")+": <strong>"+d.age+"</strong></span><span>"+t("lbl_gender")+": <strong>"+esc(genderTxt)+"</strong></span><span>"+t("lbl_height")+": <strong>"+d.height+esc(t("unit_cm"))+"</strong></span><span>"+t("lbl_weight")+": <strong>"+d.weight+esc(t("unit_kg"))+"</strong></span><span>BMI: <strong>"+esc(d.bmi)+"</strong></span><span>"+t("lbl_blood")+": <strong>"+esc(bloodTxt)+"</strong></span>";var curArr=(lang==="en"&&p.current_en)?p.current_en:p.current;$("pmDiag").innerHTML=curArr.map(function(x){return'<span class="tag">'+esc(x)+'</span>'}).join("");var alArr2=(lang==="en"&&p.allergy_en)?p.allergy_en:p.allergy;$("pmAllergy").innerHTML=alArr2.length?alArr2.map(function(a){return'<span class="pm-allergy-pill">'+SVG_WARN+' '+esc(a)+'</span>'}).join(""):'<span style="font-size:.82rem;color:var(--text-muted)">'+esc(t("none"))+'</span>';var medArr=(lang==="en"&&p.meds_en)?p.meds_en:p.meds;$("pmMeds").innerHTML=medArr.map(function(x){return"<span>"+esc(x)+"</span>"}).join("");var histArr=(lang==="en"&&p.hist_en)?p.hist_en:p.hist;$("pmHist").innerHTML=histArr.map(function(x){return"<span>"+esc(x)+"</span>"}).join("");document.querySelectorAll(".pm-tab").forEach(function(tb,i){tb.classList.toggle("active",i===0)});document.querySelectorAll(".pm-pane").forEach(function(pn,i){pn.classList.toggle("active",i===0)});$("patModal").classList.add("vis")}
function closeModal(){$("patModal").classList.remove("vis");curModal=null}
$("closeModal").onclick=closeModal;
$("patModal").onclick=function(e){if(e.target===$("patModal"))closeModal()};
document.querySelectorAll(".pm-tab").forEach(function(tab){tab.onclick=function(){document.querySelectorAll(".pm-tab").forEach(function(tb){tb.classList.remove("active")});document.querySelectorAll(".pm-pane").forEach(function(pn){pn.classList.remove("active")});tab.classList.add("active");var pane=$(tab.dataset.pt);if(pane)pane.classList.add("active")}});
